CREATE TABLE t_p79710325_user_profile_dashboa.warehouse_transactions (id SERIAL PRIMARY KEY, item_id INTEGER NOT NULL REFERENCES t_p79710325_user_profile_dashboa.warehouse_items(id), work_order_id INTEGER REFERENCES t_p79710325_user_profile_dashboa.work_orders(id), type VARCHAR(10) NOT NULL CHECK (type IN ('income', 'expense')), quantity NUMERIC(10,2) NOT NULL, price NUMERIC(12,2), note TEXT, created_by INTEGER REFERENCES t_p79710325_user_profile_dashboa.users(id), created_at TIMESTAMPTZ DEFAULT NOW())
